# Unit Tests for `celsius_to_fahrenheit`

```python
import math
import pytest

from your_module import celsius_to_fahrenheit  # adjust the import to your module


class TestCelsiusToFahrenheitHappyPath:
    """Tests for typical, expected inputs."""

    def test_freezing_point_of_water(self):
        assert celsius_to_fahrenheit(0) == 32.0

    def test_boiling_point_of_water(self):
        assert celsius_to_fahrenheit(100) == 212.0

    def test_body_temperature(self):
        assert celsius_to_fahrenheit(37) == pytest.approx(98.6)

    def test_room_temperature(self):
        assert celsius_to_fahrenheit(20) == 68.0

    def test_negative_temperature(self):
        assert celsius_to_fahrenheit(-40) == -40.0  # famous crossover point

    def test_negative_freezing(self):
        assert celsius_to_fahrenheit(-10) == 14.0

    def test_float_input(self):
        assert celsius_to_fahrenheit(36.6) == pytest.approx(97.88)

    @pytest.mark.parametrize(
        "celsius, fahrenheit",
        [
            (0, 32.0),
            (100, 212.0),
            (-40, -40.0),
            (37, 98.6),
            (25, 77.0),
            (-273.15, -459.67),  # absolute zero
        ],
    )
    def test_known_conversions(self, celsius, fahrenheit):
        assert celsius_to_fahrenheit(celsius) == pytest.approx(fahrenheit)


class TestCelsiusToFahrenheitEdgeCases:
    """Tests for boundary and unusual valid inputs."""

    def test_absolute_zero(self):
        assert celsius_to_fahrenheit(-273.15) == pytest.approx(-459.67)

    def test_very_large_positive_value(self):
        result = celsius_to_fahrenheit(1e6)
        assert result == pytest.approx(1e6 * 9 / 5 + 32)

    def test_very_large_negative_value(self):
        result = celsius_to_fahrenheit(-1e6)
        assert result == pytest.approx(-1e6 * 9 / 5 + 32)

    def test_very_small_positive_value(self):
        assert celsius_to_fahrenheit(1e-10) == pytest.approx(32.0)

    def test_zero_returns_float(self):
        result = celsius_to_fahrenheit(0)
        # The expression `c * 9/5 + 32` always returns a float
        assert isinstance(result, float)

    def test_integer_input_returns_float(self):
        result = celsius_to_fahrenheit(50)
        assert isinstance(result, float)

    def test_boolean_true_treated_as_one(self):
        # bool is a subclass of int in Python
        assert celsius_to_fahrenheit(True) == pytest.approx(33.8)

    def test_boolean_false_treated_as_zero(self):
        assert celsius_to_fahrenheit(False) == 32.0

    def test_positive_infinity(self):
        result = celsius_to_fahrenheit(math.inf)
        assert result == math.inf

    def test_negative_infinity(self):
        result = celsius_to_fahrenheit(-math.inf)
        assert result == -math.inf

    def test_nan_input(self):
        result = celsius_to_fahrenheit(math.nan)
        assert math.isnan(result)

    def test_precision_floating_point(self):
        # Make sure floating-point arithmetic is reasonable
        assert celsius_to_fahrenheit(0.1) == pytest.approx(32.18)


class TestCelsiusToFahrenheitErrorCases:
    """Tests for invalid inputs that should raise errors."""

    def test_string_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit("100")

    def test_none_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit(None)

    def test_list_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit([100])

    def test_dict_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit({"temp": 100})

    def test_tuple_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit((100,))

    def test_complex_returns_complex(self):
        # complex numbers don't raise; they propagate. Document the behavior.
        result = celsius_to_fahrenheit(complex(100, 0))
        assert result == complex(212, 0)

    def test_object_without_arithmetic_raises_type_error(self):
        class Dummy:
            pass

        with pytest.raises(TypeError):
            celsius_to_fahrenheit(Dummy())

    def test_no_argument_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit()  # type: ignore[call-arg]

    def test_too_many_arguments_raises_type_error(self):
        with pytest.raises(TypeError):
            celsius_to_fahrenheit(1, 2)  # type: ignore[call-arg]
